<?php
$pageTitle='Commissions';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('commissions');
$pdo=getDB();$employees=$pdo->query('SELECT * FROM '.table('employees').' WHERE status="active" ORDER BY first_name,last_name')->fetchAll();$plans=$pdo->query('SELECT * FROM '.table('commission_plans').' WHERE status="active" ORDER BY plan_name')->fetchAll();$invoices=$pdo->query('SELECT id,invoice_number,customer_name,total,status FROM '.table('invoices').' ORDER BY created_at DESC LIMIT 200')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'');
    if($action==='create_plan'){
      $code=preg_replace('/[^A-Z0-9_\\-]/','',strtoupper((string)$_POST['plan_code']));$pdo->prepare('INSERT INTO '.table('commission_plans').' (plan_code,plan_name,commission_type,commission_rate,threshold_amount,status,notes) VALUES (?,?,?,?,?,"active",?)')->execute([$code,trim((string)$_POST['plan_name']),trim((string)$_POST['commission_type']),max(0,(float)$_POST['commission_rate']),max(0,(float)$_POST['threshold_amount']),trim((string)$_POST['notes'])]);flash('success','Commission plan created.');
    }elseif($action==='create_record'){
      createCommissionFromSale($pdo,(int)$_POST['employee_id'],(int)$_POST['plan_id'],max(0,(float)$_POST['sale_amount']),(int)($_POST['invoice_id']??0)?:null,null,trim((string)$_POST['notes']));flash('success','Commission record created.');
    }elseif($action==='approve'){
      $pdo->prepare('UPDATE '.table('commission_records').' SET status="approved" WHERE id=?')->execute([(int)$_POST['id']]);flash('success','Commission approved.');
    }elseif($action==='pay'){
      $pdo->prepare('UPDATE '.table('commission_records').' SET status="paid" WHERE id=? AND status="approved"')->execute([(int)$_POST['id']]);flash('success','Commission marked paid.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'commissions']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/commissions.php');
}
$records=$pdo->query('SELECT r.*,e.employee_code,e.first_name,e.last_name,p.plan_name,i.invoice_number FROM '.table('commission_records').' r LEFT JOIN '.table('employees').' e ON e.id=r.employee_id LEFT JOIN '.table('commission_plans').' p ON p.id=r.commission_plan_id LEFT JOIN '.table('invoices').' i ON i.id=r.invoice_id ORDER BY r.created_at DESC LIMIT 250')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Sales Incentives</div><h2 class="h4 mb-1">Commissions</h2><p class="text-secondary mb-0">Manage commission plans and commission records for employees or sales users.</p></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/sales-pipeline.php"><?php echo t('Sales Pipeline', 'مسار المبيعات'); ?></a></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_record"><h2 class="h5 mb-3">Create Commission</h2><label class="form-label">Employee</label><select class="form-select mb-2" name="employee_id"><?php foreach($employees as $e): ?><option value="<?php echo (int)$e['id']; ?>"><?php echo esc(employeeLabel($e)); ?></option><?php endforeach; ?></select><label class="form-label">Plan</label><select class="form-select mb-2" name="plan_id"><?php foreach($plans as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc($p['plan_code'].' · '.$p['plan_name']); ?></option><?php endforeach; ?></select><label class="form-label">Invoice</label><select class="form-select mb-2" name="invoice_id"><option value="0">Manual / no invoice</option><?php foreach($invoices as $inv): ?><option value="<?php echo (int)$inv['id']; ?>"><?php echo esc($inv['invoice_number'].' · '.$inv['customer_name'].' · '.money($inv['total'])); ?></option><?php endforeach; ?></select><label class="form-label">Sale Amount</label><input class="form-control mb-2" type="number" step="0.01" name="sale_amount" value="0"><label class="form-label">Notes</label><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Commission</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="create_plan"><h2 class="h5 mb-3">Create Plan</h2><input class="form-control mb-2" name="plan_code" placeholder="PLAN-3PCT"><input class="form-control mb-2" name="plan_name" placeholder="Plan name"><select class="form-select mb-2" name="commission_type"><option value="invoice_percent">Invoice %</option><option value="sales_order_percent">Sales Order %</option></select><input class="form-control mb-2" type="number" step="0.01" name="commission_rate" placeholder="Rate %"><input class="form-control mb-2" type="number" step="0.01" name="threshold_amount" placeholder="Threshold"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Create Plan</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive"><table class="table align-middle"><thead><tr><th>Commission</th><th>Employee</th><th>Plan</th><th>Sale</th><th>Commission</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($records as $row): ?><tr><td><strong><?php echo esc($row['commission_number']); ?></strong><div class="small text-secondary"><?php echo esc($row['invoice_number']?:$row['notes']); ?></div></td><td><?php echo esc(($row['employee_code']?:'').' '.$row['first_name'].' '.$row['last_name']); ?></td><td><?php echo esc($row['plan_name']); ?></td><td><?php echo money($row['sale_amount']); ?></td><td><?php echo money($row['commission_amount']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($row['status'])); ?>"><?php echo esc($row['status']); ?></span></td><td class="text-end"><?php if($row['status']==='earned'): ?><form method="post" class="d-inline"><input type="hidden" name="action" value="approve"><input type="hidden" name="id" value="<?php echo (int)$row['id']; ?>"><button class="btn btn-sm btn-outline-success">Approve</button></form><?php endif; ?><?php if($row['status']==='approved'): ?><form method="post" class="d-inline"><input type="hidden" name="action" value="pay"><input type="hidden" name="id" value="<?php echo (int)$row['id']; ?>"><button class="btn btn-sm btn-brand">Pay</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$records): ?><tr><td colspan="7" class="text-secondary">No commission records yet.</td></tr><?php endif; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>